@@ -0,0 +1,129 @@
+import { useState } from "react";
+import axios from "axios";
+import { Database, Download, Upload } from "lucide-react";
+
+const BackupRecovery = () => {
+  const [loading, setLoading] = useState(false);
+  const [message, setMessage] = useState("");
+  const [backupPath, setBackupPath] = useState("");
+
+  // Backup Database
+  const handleBackup = async () => {
+  try {
+    setLoading(true);
+    setMessage("Creating database backup...");
+
+    const { data } = await axios.post(
+      "http://localhost:8000/api/v1/admin/backup"
+    );
+
+    setBackupPath(data.backupPath);
+    setMessage("✅ Database backup completed successfully.");
+  } catch (error) {
+    console.error(error);
+
+    setMessage(
+      error.response?.data?.message ||
+      "❌ Database backup failed."
+    );
+  } finally {
+    setLoading(false);
+  }
+};
+
+  // Restore Database
+  const handleRestore = async () => {
+    try {
+      setLoading(true);
+
+      const { data } = await axios.post(
+        "http://localhost:8000/api/v1/admin/restore",
+        {
+          backupPath,
+        }
+      );
+
+      setMessage(data.message);
+
+    } catch (error) {
+      setMessage(
+        error.response?.data?.message || "Restore Failed"
+      );
+    } finally {
+      setLoading(false);
+    }
+  };
+
+  return (
+    <div className="max-w-4xl mx-auto mt-10">
+
+      <div className="bg-white rounded-xl shadow-lg p-8">
+
+        <h1 className="text-3xl font-bold mb-8 flex items-center gap-3">
+          <Database size={32} />
+          Backup & Recovery
+        </h1>
+
+        <div className="space-y-6">
+
+          <div className="border rounded-lg p-4">
+            <h2 className="font-semibold text-xl mb-2">
+              Database Backup
+            </h2>
+
+            <button
+  onClick={handleBackup}
+  disabled={loading}
+  className={`px-6 py-3 rounded-lg text-white font-semibold ${
+    loading
+      ? "bg-gray-400 cursor-not-allowed"
+      : "bg-green-600 hover:bg-green-700"
+  }`}
+>
+  {loading ? "Backing Up..." : "Backup Database"}
+</button>
+          </div>
+
+          <div className="border rounded-lg p-4">
+            <h2 className="font-semibold text-xl mb-2">
+              Database Restore
+            </h2>
+
+            <button
+              onClick={handleRestore}
+              disabled={loading}
+              className="bg-red-600 hover:bg-red-700 text-white px-6 py-3 rounded-lg"
+            >
+              Restore Database
+            </button>
+          </div>
+
+          <div className="border rounded-lg p-4">
+            <h2 className="font-semibold">
+              Backup Location
+            </h2>
+
+            <p className="text-gray-600 break-all">
+              {backupPath || "No Backup Yet"}
+            </p>
+          </div>
+
+          <div className="border rounded-lg p-4">
+            <h2 className="font-semibold">
+              Status
+            </h2>
+
+            <p>
+              {message || "Waiting..."}
+            </p>
+          </div>
+
+        </div>
+
+      </div>
+
+    </div>
+  );
+};
+
+export default BackupRecovery;
